import (
	"fmt"
	"os"
	"strconv"
)

func main() {
	mode := os.Args[1]
	shift, _ := strconv.Atoi(os.Args[2])
	message := os.Args[3]

	if mode == "decode" {
		shift = -shift
	}

	shift = ((shift % 26) + 26) % 26

	result := make([]byte, len(message))
	for i := 0; i < len(message); i++ {
		c := message[i]
		if c >= 'A' && c <= 'Z' {
			result[i] = 'A' + (c-'A'+byte(shift))%26
		} else if c >= 'a' && c <= 'z' {
			result[i] = 'a' + (c-'a'+byte(shift))%26
		} else {
			result[i] = c
		}
	}

	fmt.Println(string(result))
}
